fun solve(nums: Array<Long>, k: Long): Long {
    val n = nums.size
    if (n == 0) return -1L

    // 1. Calculate Prefix Maximums (LMax)
    val lMax = LongArray(n)
    lMax[0] = nums[0]
    for (i in 1 until n) {
        lMax[i] = maxOf(lMax[i - 1], nums[i])
    }

    // 2. Calculate Suffix Minimums (RMin)
    val rMin = LongArray(n)
    rMin[n - 1] = nums[n - 1]
    for (i in n - 2 downTo 0) {
        rMin[i] = minOf(rMin[i + 1], nums[i])
    }

    // 3. Iterate and check the stability condition
    for (i in 0 until n) {
        // Instability value = max(nums[0..i]) - min(nums[i..n-1])
        val instabilityValue = lMax[i] - rMin[i]

        if (instabilityValue <= k) {
            // Return the smallest stable index
            return i.toLong()
        }
    }

    // If no stable index is found
    return -1L
}

